${pagingTop}
SELECT

FROM
    TRAINING_BOOK_MANAGE
WHERE
    homepage_id = #{homepage_id}
AND training_idx = #{training_idx}

    AND	${search_type} LIKE '%'||#{search_text}||'%'


    AND training_status = #{attendance_status}


    AND TO_CHAR(add_date, 'YYYY-MM-DD') >= #{search_start_date}


    AND TO_CHAR(add_date, 'YYYY-MM-DD') <= #{search_end_date}


    AND qr_count = #{qr_count}

ORDER BY
    add_date desc
